export default function DocActions({ clientId, docs }: { clientId: string, docs: any[] }) {
            const [selected, setSelected] = React.useState<string>("");
            const [action, setAction] = React.useState<string>("verify");
            const [reason, setReason] = React.useState<string>("");
            const [fileName, setFileName] = React.useState<string>("");
            const [status, setStatus] = React.useState<"idle"|"pending"|"done"|"error">("idle");
            const [msg, setMsg] = React.useState<string>("");

            const actionableDocs = (docs || []).filter((d: any) =>
              d.status === "received" || d.status === "needs_review" || d.status === "missing"
            );

            const handleSubmit = async () => {
              if (!selected) { setMsg("Select a document."); return; }
              if (action === "reject" && !reason) { setMsg("A reason is required for rejection."); return; }
              if (action === "receive" && !fileName) { setMsg("A file name is required to mark as received."); return; }
              setStatus("pending");
              setMsg("");
              try {
                const body: any = { action };
                if (action === "receive") body.fileName = fileName;
                if (action === "reject") body.reason = reason;
                const result = await tools.host_setDocumentStatus({ id: clientId, docId: selected, body });
                if (result?.status === "pending-approval") {
                  setStatus("pending");
                  setMsg("Awaiting approval before the document status is updated.");
                } else {
                  setStatus("done");
                  setMsg("Document status updated.");
                }
              } catch (e: any) {
                setStatus("error");
                setMsg(e?.message || "Something went wrong.");
              }
            };

            if (!actionableDocs.length) return (
              <Surface>
                <Text variant="caption" text="No documents available to action right now."/>
              </Surface>
            );

            return (
              <Surface>
                <Stack gap={3}>
                  <Text variant="heading" text="Update document status"/>
                  <Select
                    label="Document"
                    options={actionableDocs}
                    labelField="name"
                    valueField="id"
                    value={selected}
                    placeholder="Choose a document…"
                    onChange={(v: string) => setSelected(v)}
                  />
                  <Select
                    label="Action"
                    options={[
                      { label: "Verify (mark correct)", value: "verify" },
                      { label: "Reject (return to missing)", value: "reject" },
                      { label: "Receive (mark uploaded)", value: "receive" }
                    ]}
                    labelField="label"
                    valueField="value"
                    value={action}
                    onChange={(v: string) => setAction(v)}
                  />
                  {action === "receive" && (
                    <Input
                      label="File name"
                      value={fileName}
                      placeholder="e.g. W2_2025.pdf"
                      onChange={(v: string) => setFileName(v)}
                    />
                  )}
                  {action === "reject" && (
                    <Textarea
                      label="Rejection reason (visible to client)"
                      value={reason}
                      placeholder="Explain what needs to be corrected…"
                      rows={3}
                      onChange={(v: string) => setReason(v)}
                    />
                  )}
                  {msg && (
                    <Callout tone={status === "error" ? "danger" : status === "done" ? "success" : "info"} title={msg}/>
                  )}
                  <Button
                    label={status === "pending" ? "Awaiting approval…" : "Apply"}
                    variant="primary"
                    disabled={status === "pending"}
                    onClick={handleSubmit}
                  />
                </Stack>
              </Surface>
            );
          }

components.MessageThread:
export default function MessageThread({ messages, clientId }: { messages: any[], clientId: string }) {
            const [body, setBody] = React.useState<string>("");
            const [status, setStatus] = React.useState<"idle"|"pending"|"done"|"error">("idle");
            const [msg, setMsg] = React.useState<string>("");
            const bottomRef = React.useRef<HTMLDivElement>(null);

            React.useEffect(() => {
              bottomRef.current?.scrollIntoView({ behavior: "smooth" });
            }, [messages]);

            const handleSend = async () => {
              if (!body.trim()) return;
              setStatus("pending");
              setMsg("");
              try {
                const result = await tools.host_sendClientMessage({
                  id: clientId,
                  body: { body: body.trim(), author: "firm" }
                });
                if (result?.status === "pending-approval") {
                  setStatus("pending");
                  setMsg("Message is awaiting approval before delivery.");
                } else {
                  setStatus("done");
                  setBody("");
                  setMsg("Message sent.");
                }
              } catch (e: any) {
                setStatus("error");
                setMsg(e?.message || "Failed to send message.");
              }
            };

            const sorted = [...(messages || [])];

            return (
              <Stack gap={3}>
                <Surface>
                  <Stack gap={2} style={{ maxHeight: 420, overflowY: "auto" }}>
                    {sorted.length === 0 && (
                      <Text variant="caption" text="No messages yet. Send one below to start the conversation."/>
                    )}
                    {sorted.map((m: any, i: number) => {
                      const isFirm = m.author === "firm" || m.direction === "outbound";
                      return (
                        <div
                          key={m.id || i}
                          style={{
                            display: "flex",
                            flexDirection: "column",
                            alignItems: isFirm ? "flex-end" : "flex-start"
                          }}
                        >
                          <div style={{
                            background: isFirm ? "var(--vendo-color-accent)" : "var(--vendo-color-surface)",
                            color: isFirm ? "var(--vendo-color-accent-text)" : "var(--vendo-color-text)",
                            border: isFirm ? "none" : "1px solid var(--vendo-color-border)",
                            borderRadius: "var(--vendo-radius-medium)",
                            padding: "10px 14px",
                            maxWidth: "80%",
                            fontSize: "var(--vendo-font-size)",
                            fontFamily: "var(--vendo-font-family)"
                          }}>
                            {m.body}
                          </div>
                          <span style={{
                            fontSize: "12px",
                            color: "var(--vendo-color-muted)",
                            marginTop: 2,
                            fontFamily: "var(--vendo-font-family)"
                          }}>
                            {isFirm ? "Firm" : "Client"} · {m.sentAt ? fmt.dateTime(m.sentAt) : ""}
                          </span>
                        </div>
                      );
                    })}
                    <div ref={bottomRef}/>
                  </Stack>
                </Surface>
                <Stack gap={2}>
                  <Textarea
                    label="New message"
                    value={body}
                    placeholder="Write a message to the client…"
                    rows={3}
                    onChange={(v: string) => setBody(v)}
                  />
                  {msg && (
                    <Callout tone={status === "error" ? "danger" : status === "done" ? "success" : "info"} title={msg}/>
                  )}
                  <Button
                    label={status === "pending" ? "Awaiting approval…" : "Send message"}
                    variant="primary"
                    disabled={status === "pending" || !body.trim()}
                    onClick={handleSend}
                  />
                </Stack>
              </Stack>
            );
          }
